function ClientDetails(props) {
  return (
    <div className="container">
      <div className="row">
        <div className="btn" onClick={() => props.navigation.go("Home")}>
          Enviar
        </div>
        <div className="btn" onClick={props.navigation.back}>
          Back
        </div>
      </div>
      <div className="row">
        <h1>ClientDetails</h1>
      </div>
    </div>
  );
}

export default ClientDetails;
